import{_ as n,o,c as a,a8 as t}from"./chunks/framework.DvHWw5tv.js";const p=JSON.parse('{"title":"mengyue-plus","description":"","frontmatter":{},"headers":[],"relativePath":"plugin/mengyuePlus.md","filePath":"plugin/mengyuePlus.md"}'),s={name:"plugin/mengyuePlus.md"};function r(l,e,c,i,d,u){return o(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[t('<h1 id="mengyue-plus" tabindex="-1">mengyue-plus <a class="header-anchor" href="#mengyue-plus" aria-label="Permalink to “mengyue-plus”">​</a></h1><p><code>mengyue-plus</code> 是本组件库体系在正式发布前的 <strong>早期过渡版本</strong>。它承载了组件库最初的设计理念与功能实现，并为后续正式版的完善奠定了坚实的基础。</p><h2 id="定位与现状" tabindex="-1">定位与现状 <a class="header-anchor" href="#定位与现状" aria-label="Permalink to “定位与现状”">​</a></h2><p><code>mengyue-plus</code> 与正式版 <code>mengyue-components</code> 在组件种类上 <strong>完全一致</strong>，所有基础组件功能均已具备。该版本曾用于内部验证与早期项目试用，随着正式版的推出，<code>mengyue-plus</code> 已进入 <strong>维护冻结</strong> 状态，不再进行新功能开发。</p><h2 id="技术特征" tabindex="-1">技术特征 <a class="header-anchor" href="#技术特征" aria-label="Permalink to “技术特征”">​</a></h2><ul><li><strong>技术栈</strong>：Vue 3 + TypeScript + Vite，基于 pnpm workspace 构建。</li><li><strong>完全自研</strong>：所有组件均为独立开发，未依赖任何第三方 UI 库。</li><li><strong>测试保障</strong>：包含 200+ 个测试用例，单元测试覆盖率 100%。</li><li><strong>轻量设计</strong>：打包体积控制在数百 KB 级别（&lt; 1MB），按需引入成本极低。</li></ul><h2 id="与正式版的关系" tabindex="-1">与正式版的关系 <a class="header-anchor" href="#与正式版的关系" aria-label="Permalink to “与正式版的关系”">​</a></h2><p><code>mengyue-plus</code> 与 <code>mengyue-components</code> 存在 <strong>继承与优化关系</strong>：</p><ul><li>正式版在保留全部组件功能的基础上，<strong>统一并优化了 Props API 设计</strong>，提升了使用一致性。</li><li>修复了早期版本中已发现的缺陷，增强了代码健壮性与可维护性。</li></ul><div class="warning custom-block"><p class="custom-block-title">迁移建议</p><p>当前项目若仍在使用 <code>mengyue-plus</code>，<strong>强烈推荐迁移至正式版 <code>mengyue-components</code></strong>。<br> 迁移路径与变更点请参考独立的 <a href="./../question/migration.html">迁移指南</a> 章节。</p></div><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ul><li><code>mengyue-plus</code> 与 <code>mengyue-components</code> 虽可共存于同一项目，但二者为同一套组件的不同迭代，<strong>无必要同时引入</strong>。</li><li>后续所有新特性与问题修复将 <strong>在 <code>mengyue-components</code> 进行</strong>。</li></ul><p>对于新项目，请直接选用 <code>mengyue-components</code> 以获得最新的 API 设计与长期维护支持。</p>',13)])])}const m=n(s,[["render",r]]);export{p as __pageData,m as default};
